body:
The following MLIR code:
```mlir
module  {
  calyx.program  {
    calyx.component @main(%in0: i32, %in1: i32, %in2: i32, %clk: i1, %reset: i1, %go: i1) -> (%out0: i32, %done: i1) {
      %true = hw.constant true
      %c0_i32 = hw.constant 0 : i32
      %while_0_arg2_reg.in, %while_0_arg2_reg.write_en, %while_0_arg2_reg.clk, %while_0_arg2_reg.reset, %while_0_arg2_reg.out, %while_0_arg2_reg.done = calyx.register "while_0_arg2_reg" : i32, i1, i1, i1, i32, i1
      %while_0_arg1_reg.in, %while_0_arg1_reg.write_en, %while_0_arg1_reg.clk, %while_0_arg1_reg.reset, %while_0_arg1_reg.out, %while_0_arg1_reg.done = calyx.register "while_0_arg1_reg" : i32, i1, i1, i1, i32, i1
      %while_0_arg0_reg.in, %while_0_arg0_reg.write_en, %while_0_arg0_reg.clk, %while_0_arg0_reg.reset, %while_0_arg0_reg.out, %while_0_arg0_reg.done = calyx.register "while_0_arg0_reg" : i32, i1, i1, i1, i32, i1
      %bb2_arg1_reg.in, %bb2_arg1_reg.write_en, %bb2_arg1_reg.clk, %bb2_arg1_reg.reset, %bb2_arg1_reg.out, %bb2_arg1_reg.done = calyx.register "bb2_arg1_reg" : i32, i1, i1, i1, i32, i1
      %bb2_arg0_reg.in, %bb2_arg0_reg.write_en, %bb2_arg0_reg.clk, %bb2_arg0_reg.reset, %bb2_arg0_reg.out, %bb2_arg0_reg.done = calyx.register "bb2_arg0_reg" : i32, i1, i1, i1, i32, i1
      calyx.wires  {
        calyx.group @assign_while_0_init  {
          calyx.assign %while_0_arg0_reg.in = %in0 : i32
          calyx.assign %while_0_arg0_reg.write_en = %true : i1
          calyx.assign %while_0_arg1_reg.in = %c0_i32 : i32
          calyx.assign %while_0_arg1_reg.write_en = %true : i1
          calyx.assign %while_0_arg2_reg.in = %c0_i32 : i32
          calyx.assign %while_0_arg2_reg.write_en = %true : i1
          %0 = comb.and %while_0_arg0_reg.done, %while_0_arg1_reg.done : i1
          %1 = comb.and %0, %while_0_arg2_reg.done : i1
          calyx.group_done %1 : i1
        }
      }
      calyx.control  {
        calyx.enable @assign_while_0_init
      }
    }
  }
}
```

Generates the following assignment in the Calyx code using `circt-translate --export-calyx`:
```
      assign_while_0_init[done] = ((while_0_arg0_reg.done & while_0_arg1_reg.done) & while_0_arg2_reg.done);
```
This is incorrect. Calyx does not allow for complex guard statements to be assigned to ports. It should instead be:
```
 assign_while_0_init[done] = ((while_0_arg0_reg.done & while_0_arg1_reg.done) & while_0_arg2_reg.done) ? 1'd1;
```

The problem is that that guard inliner for the emitter incorrectly transforms `calyx.group_done %1 : i1` into the above by recursively inlining `%1`.

Two possible solutions are:
1. Always using `calyx.group_done %true, %1 ?` or something so that there is an explicit port
2. Making the emitter less smart and just structurally instantiate the wires into the relevant subcomponent like `std_add` etc.
